import React, { useEffect } from 'react';
import { motion } from 'framer-motion';

export default function CurtainReveal({ isVisible, onAnimationComplete }) {
  useEffect(() => {
    if (isVisible) {
      // Call completion callback after animation (1.5s)
      const timer = setTimeout(() => {
        onAnimationComplete?.();
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [isVisible, onAnimationComplete]);

  if (!isVisible) return null;

  return (
    <>
      {/* LEFT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "-100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        className="fixed top-0 left-0 h-full w-1/2 bg-cover z-20"
        style={{
          backgroundImage: 'linear-gradient(90deg, rgba(26,31,58,0.9) 0%, rgba(26,31,58,0.5) 50%, transparent 100%)',
          backgroundSize: 'cover'
        }}
      />

      {/* RIGHT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        className="fixed top-0 right-0 h-full w-1/2 bg-cover z-20"
        style={{
          backgroundImage: 'linear-gradient(270deg, rgba(26,31,58,0.9) 0%, rgba(26,31,58,0.5) 50%, transparent 100%)',
          backgroundSize: 'cover'
        }}
      />
    </>
  );
}
